import{_ as a,c as i,a2 as s,o as t}from"./chunks/framework.CKjLqgBu.js";const g=JSON.parse('{"title":"Streaming Refactor Plan","description":"","frontmatter":{"head":[]},"headers":[],"relativePath":"plans/2026-03-17-kiro-refactor-streaming-plan.md","filePath":"plans/2026-03-17-kiro-refactor-streaming-plan.md","lastUpdated":null}'),o={name:"plans/2026-03-17-kiro-refactor-streaming-plan.md"};function r(n,e,d,c,l,h){return t(),i("div",null,e[0]||(e[0]=[s('<h1 id="streaming-refactor-plan" tabindex="-1">Streaming Refactor Plan <a class="header-anchor" href="#streaming-refactor-plan" aria-label="Permalink to &quot;Streaming Refactor Plan&quot;">​</a></h1><p><em>Generated: 2026-03-17</em></p><h2 id="current-architecture" tabindex="-1">Current Architecture <a class="header-anchor" href="#current-architecture" aria-label="Permalink to &quot;Current Architecture&quot;">​</a></h2><p>The streaming domain is spread across multiple layers:</p><p><strong>Layer 1 — Core engine</strong> (<code>core/device/streaming/</code>)</p><ul><li><code>Stream</code> (VDSI subclass) — main streaming state machine</li><li><code>StreamingHandler</code>, <code>CloudStreamingHandler</code>, <code>UserIdleHandler</code>, <code>VisibilityHandler</code>, etc. — pluggable handlers</li></ul><p><strong>Layer 2 — Portal-side device services</strong> (<code>src/models/</code>)</p><ul><li><code>UIService</code> — owns <code>streamIndex</code>, <code>playbackIndex</code>, <code>volume</code>, <code>muted</code>, <code>zoom</code>, <code>pipInfo</code>, <code>presetInfo</code>, etc.</li><li><code>RecordingService</code> — owns recording interval/dates queries, references <code>stream.state</code> and <code>stream.isLiveview</code></li><li><code>VideoStreamService</code> — owns video codec/resolution settings (device config, not playback)</li><li><code>TwoWayAudioService</code> + <code>MicrophoneStreamer</code> — RTSP back-channel audio</li></ul><p><strong>Layer 3 — View preferences</strong> (<code>src/models/CustomizedView/</code>)</p><ul><li><code>CustomizedViewPreferencesManager</code> — syncs <code>UIService</code> + <code>stream.state</code> to/from saved view cells</li><li><code>CustomizedView</code> — owns layout, cells, pagination</li></ul><p><strong>Layer 4 — UI components</strong> (<code>src/components/</code>, <code>src/pages/</code>)</p><ul><li><code>PlayerWrapper</code>, <code>reskin/PlayerWrapper</code> — two parallel implementations</li><li><code>PlayerControl</code>, <code>reskin/PlayerControl</code> — two parallel implementations</li><li><code>PlayerCenterControls</code>, <code>PlayerLeftControls</code>, <code>PlayerRightControls</code> — control bar fragments</li><li><code>EventPlayer</code> — playback in notification modal</li><li><code>PlaybackExportArchivePlayerPanel</code> — playback in export modal</li><li><code>ArchivePlayerPanel</code> — playback in archive management</li></ul><hr><h2 id="problems-identified" tabindex="-1">Problems Identified <a class="header-anchor" href="#problems-identified" aria-label="Permalink to &quot;Problems Identified&quot;">​</a></h2><h3 id="_1-duplicated-state-between-uiservice-and-stream" tabindex="-1">1. Duplicated state between <code>UIService</code> and <code>Stream</code> <a class="header-anchor" href="#_1-duplicated-state-between-uiservice-and-stream" aria-label="Permalink to &quot;1. Duplicated state between `UIService` and `Stream`&quot;">​</a></h3><p><code>streamIndex</code>, <code>playbackIndex</code>, <code>pipInfo</code>, <code>presetInfo</code>, <code>volume</code>, <code>muted</code>, <code>stretch</code>, <code>dewarpType</code>, <code>enableDigitalZoom</code> all exist in <strong>both</strong> <code>UIService.state</code> and <code>Stream.state</code>. <code>CustomizedViewPreferencesManager.applyPreference()</code> writes to both manually. This is the root cause of most sync bugs.</p><div class="language-js vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// UIService owns it</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">state.streamIndex </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> DEFAULT_STREAM_INDEX</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">VSAAS_CAMERA</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">LIVE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Stream also owns it</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">streamIndex</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: options?.streamIndex </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">??</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// PreferencesManager syncs both manually</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ui.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">updateState</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(preferences);</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">stream.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">updateState</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(preferences);</span></span></code></pre></div><h3 id="_2-recordingservice-reaches-into-stream-state-directly" tabindex="-1">2. <code>RecordingService</code> reaches into <code>stream.state</code> directly <a class="header-anchor" href="#_2-recordingservice-reaches-into-stream-state-directly" aria-label="Permalink to &quot;2. `RecordingService` reaches into `stream.state` directly&quot;">​</a></h3><div class="language-js vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">get </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">isLiveview</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">() {</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  return</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> this</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.reference.services.stream?.isLiveview;</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">get </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">currentResolutionIndex</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">() {</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  const</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">streamIndex</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">playbackIndex</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> } </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> this</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.reference.services.stream.state;</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  ...</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">get </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">isCloudStreaming</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">() {</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  return</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> this</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">getRootReference</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">()?.services.stream?.isCloudStreaming;</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><code>RecordingService</code> is tightly coupled to <code>Stream</code>&#39;s internal state shape. Any refactor of <code>Stream</code> breaks <code>RecordingService</code>.</p><h3 id="_3-two-parallel-player-component-trees" tabindex="-1">3. Two parallel player component trees <a class="header-anchor" href="#_3-two-parallel-player-component-trees" aria-label="Permalink to &quot;3. Two parallel player component trees&quot;">​</a></h3><p><code>src/components/Player/PlayerWrapper.vue</code> and <code>src/components/reskin/Player/PlayerWrapper.vue</code> exist side-by-side. Same for <code>PlayerControl</code>. The reskin versions are the future, but both are actively used, creating maintenance burden.</p><h3 id="_4-twowayaudioservice-uses-console-warn-for-control-flow-logging" tabindex="-1">4. <code>TwoWayAudioService</code> uses <code>console.warn</code> for control flow logging <a class="header-anchor" href="#_4-twowayaudioservice-uses-console-warn-for-control-flow-logging" aria-label="Permalink to &quot;4. `TwoWayAudioService` uses `console.warn` for control flow logging&quot;">​</a></h3><p>The service has ~10 <code>console.warn(...)</code> calls for normal operation steps (&quot;START MIC STREAMING...&quot;, &quot;SEND RTSP OPTIONS...&quot;, etc.). These should use the project&#39;s <code>Logger</code>/<code>getTagged</code> pattern already used elsewhere.</p><h3 id="_5-customizedviewpreferencesmanager-is-a-god-object" tabindex="-1">5. <code>CustomizedViewPreferencesManager</code> is a god object <a class="header-anchor" href="#_5-customizedviewpreferencesmanager-is-a-god-object" aria-label="Permalink to &quot;5. `CustomizedViewPreferencesManager` is a god object&quot;">​</a></h3><p>It knows about <code>UIService</code>, <code>Stream</code>, VCA handler state, and the preferences schema. Any new preference requires touching this class.</p><hr><h2 id="refactor-plan" tabindex="-1">Refactor Plan <a class="header-anchor" href="#refactor-plan" aria-label="Permalink to &quot;Refactor Plan&quot;">​</a></h2><h3 id="phase-1-—-eliminate-duplicated-streaming-state-highest-impact" tabindex="-1">Phase 1 — Eliminate duplicated streaming state <em>(highest impact)</em> <a class="header-anchor" href="#phase-1-—-eliminate-duplicated-streaming-state-highest-impact" aria-label="Permalink to &quot;Phase 1 — Eliminate duplicated streaming state _(highest impact)_&quot;">​</a></h3><p><strong>Goal:</strong> <code>UIService</code> becomes the single source of truth for display preferences. <code>Stream</code> reads from <code>UIService</code> instead of owning its own copy.</p><ul><li>Remove <code>streamIndex</code>, <code>playbackIndex</code>, <code>pipInfo</code>, <code>presetInfo</code>, <code>volume</code>, <code>muted</code>, <code>stretch</code>, <code>dewarpType</code>, <code>enableDigitalZoom</code> from <code>Stream</code>&#39;s initial state</li><li><code>Stream</code> reads these via <code>this.reference.services.ui.state</code> when it needs them</li><li><code>CustomizedViewPreferencesManager.applyPreference()</code> only writes to <code>UIService</code>; <code>Stream</code> reacts reactively</li></ul><p>This eliminates the dual-write pattern and simplifies <code>CustomizedViewPreferencesManager</code>.</p><h3 id="phase-2-—-decouple-recordingservice-from-stream-internals" tabindex="-1">Phase 2 — Decouple <code>RecordingService</code> from <code>Stream</code> internals <a class="header-anchor" href="#phase-2-—-decouple-recordingservice-from-stream-internals" aria-label="Permalink to &quot;Phase 2 — Decouple `RecordingService` from `Stream` internals&quot;">​</a></h3><p><strong>Goal:</strong> <code>RecordingService</code> should not reach into <code>stream.state</code> directly.</p><ul><li>Add explicit getters on <code>Stream</code>: <code>isLiveview</code>, <code>isCloudStreaming</code>, <code>currentStreamIndex</code>, <code>currentPlaybackIndex</code></li><li><code>RecordingService</code> calls these getters instead of accessing <code>.state</code> directly</li><li>Makes the contract explicit and survives internal <code>Stream</code> refactors</li></ul><h3 id="phase-3-—-consolidate-player-component-trees" tabindex="-1">Phase 3 — Consolidate player component trees <a class="header-anchor" href="#phase-3-—-consolidate-player-component-trees" aria-label="Permalink to &quot;Phase 3 — Consolidate player component trees&quot;">​</a></h3><p><strong>Goal:</strong> Remove the legacy <code>src/components/Player/</code> tree, keep only <code>src/components/reskin/Player/</code>.</p><ul><li>Audit all usages of <code>src/components/Player/PlayerWrapper.vue</code> (used in <code>pages/group/index.vue</code>, <code>pages/view/list/</code>, etc.)</li><li>Migrate those usages to the reskin version</li><li>Delete <code>src/components/Player/PlayerWrapper.vue</code> and the duplicate <code>PlayerControl</code></li></ul><p>Do incrementally per page to reduce risk.</p><h3 id="phase-4-—-fix-twowayaudioservice-logging" tabindex="-1">Phase 4 — Fix <code>TwoWayAudioService</code> logging <a class="header-anchor" href="#phase-4-—-fix-twowayaudioservice-logging" aria-label="Permalink to &quot;Phase 4 — Fix `TwoWayAudioService` logging&quot;">​</a></h3><ul><li>Replace all <code>console.warn(...)</code> in <code>TwoWayAudioService</code> with <code>Log.debug(...)</code> / <code>Log.warn(...)</code> using the existing <code>getTagged(&#39;TwoWayAudioService&#39;, Logger.DEBUG)</code> logger already set up at the top of the file</li></ul><h3 id="phase-5-—-slim-down-customizedviewpreferencesmanager" tabindex="-1">Phase 5 — Slim down <code>CustomizedViewPreferencesManager</code> <a class="header-anchor" href="#phase-5-—-slim-down-customizedviewpreferencesmanager" aria-label="Permalink to &quot;Phase 5 — Slim down `CustomizedViewPreferencesManager`&quot;">​</a></h3><p>After Phase 1 reduces its responsibility:</p><ul><li>Extract VCA state sync into a separate <code>VcaPreferenceSyncer</code> or move it into <code>VcaHandler</code> itself</li><li><code>CustomizedViewPreferencesManager</code> should only deal with serializing/deserializing the preference list, not know about VCA internals</li></ul><hr><h2 id="suggested-order" tabindex="-1">Suggested Order <a class="header-anchor" href="#suggested-order" aria-label="Permalink to &quot;Suggested Order&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Phase</th><th>Risk</th><th>Effort</th><th>Value</th></tr></thead><tbody><tr><td>2 — Decouple RecordingService</td><td>Low</td><td>Small</td><td>High</td></tr><tr><td>4 — Fix TwoWayAudio logging</td><td>Very Low</td><td>Tiny</td><td>Medium</td></tr><tr><td>1 — Eliminate duplicate state</td><td>High</td><td>Large</td><td>Very High</td></tr><tr><td>3 — Consolidate player trees</td><td>Medium</td><td>Medium</td><td>High</td></tr><tr><td>5 — Slim PreferencesManager</td><td>Low</td><td>Small</td><td>Medium</td></tr></tbody></table><p>Start with Phase 2 and 4 (safe, quick wins). Phase 1 is the real structural fix but needs careful testing since <code>CustomizedView</code> persistence depends on the current dual-write behavior.</p>',48)]))}const k=a(o,[["render",r]]);export{g as __pageData,k as default};
